#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long K;
        scanf("%lld", &K);
        int cnt = 0;
        while ((K & 1LL) == 0) { // K is even
            cnt++;
            K >>= 1; // divide by 2
        }
        printf("%d\n", cnt);
    }
    return 0;
}

